// Return A[i][j] from CSR storage (returns 0 if not stored)
double csr_get(int i, int j, double* valori, int* ind_col, int* inceput_linii) {
    for (int k = inceput_linii[i]; k < inceput_linii[i + 1]; k++) {
        if (ind_col[k] == j) return valori[k];
    }
    return 0.0;
}

// Jacobi iteration: needs two arrays (old and new) to avoid overwrite
while (!converged) {
    for (int i = 0; i < n; i++) {
        double s = b[i];
        for (int j = 0; j < n; j++) {
            if (j != i) s -= A[i][j] * x_old[j];    // uses x^(k)
        }
        x_new[i] = s / A[i][i];                     // produces x^(k+1)
    }
    swap(x_old, x_new);
    converged = (norm(x_new - x_old) < tol);
}

// Gauss-Seidel: single array, update in place
while (!converged) {
    double max_delta = 0;
    for (int i = 0; i < n; i++) {
        double s = b[i];
        for (int j = 0; j < n; j++) {
            if (j != i) s -= A[i][j] * x[j];       // j < i uses x^(k+1), j > i uses x^(k)
        }
        double new_xi = s / A[i][i];
        max_delta = fmax(max_delta, fabs(new_xi - x[i]));
        x[i] = new_xi;                              // overwrite immediately
    }
    converged = (max_delta < tol);
}
